import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


type CalcMode = "pace" | "time" | "distance";

function formatTime(totalSeconds: number) {
  const h = Math.floor(totalSeconds / 3600);
  const m = Math.floor((totalSeconds % 3600) / 60);
  const s = Math.round(totalSeconds % 60);
  if (h > 0) return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
  return `${m}:${String(s).padStart(2, "0")}`;
}

const FAQS = [
  { q: "What is a good running pace?", a: "Average recreational runner pace: 9-11 min/mile (5:35-6:50 min/km). For race categories: 5K beginner ~35-45 min, intermediate ~25-30 min, competitive under 20 min. Half marathon: beginners ~2:30, intermediate ~2:00, competitive under 1:30. Marathon: beginner ~5:00, intermediate ~4:00, competitive under 3:00." },
  { q: "How do I convert pace to speed?", a: "Speed (mph) = 60  x  pace (min/mile). Example: 10 min/mile pace = 60  x  10 = 6 mph on the treadmill. For km: speed (km/h) = 60  x  pace (min/km). A 6:00/km pace = 10 km/h. To convert min/mile to min/km: divide pace by 1.60934." },
  { q: "What is negative splitting in running?", a: "Negative splitting means running the second half of a race faster than the first. It's the most efficient pacing strategy at most distances - it conserves glycogen early and allows a strong finish. Most marathon world records are run with slight negative splits. The opposite (going out too fast) is called positive splitting and often leads to a dramatic slowdown late in the race." },
  { q: "How do I calculate finish time for a marathon?", a: "Marathon = 26.2 miles = 42.195 km. Multiply your pace (min/mile)  x  26.2, or pace (min/km)  x  42.195 for total finish time in minutes. Example: 9:00/mile  x  26.2 = 235.8 min = 3:55:48. Use 'Calculate Time' mode in this calculator for an instant result at any pace." },
  { q: "How do I find my target pace for a goal finish time?", a: "Divide your goal finish time (in minutes) by the distance. For a sub-4:00 marathon (240 min): 240  x  26.2 = 9:09/mile. For a sub-2:00 half (120 min): 120  x  13.1 = 9:09/mile. For a sub-25:00 5K: 25  x  3.1 miles = 8:03/mile." },
  { q: "What is the difference between pace and speed?", a: "Pace = time per unit distance (min/mile or min/km). Speed = distance per unit time (mph or km/h). They are reciprocals: Speed = 60  x  Pace (in consistent units). Runners typically use pace; cyclists and coaches often use speed. Treadmills use speed; GPS watches typically display pace." },
  { q: "How do I calculate my pace from a race result?", a: "Pace = Total time (minutes)  x  Distance. Example: 5K in 24:30 = 24.5 min  x  3.1 miles = 7:54/mile, or 24.5  x  5 km = 4:54/km. Use the 'Calculate Pace' mode with your actual finish time and distance for precise results." },
  { q: "What is a training pace vs. race pace?", a: "Easy training runs should be 60-90 seconds per mile slower than your goal race pace - this builds aerobic base without overtraining. Tempo runs are typically 20-30 sec/mile slower than 10K race pace. Intervals target 5K pace or faster. Only races and tune-up race simulations should hit true race pace." },
];

const RACE_PACES = [
  ["5K (3.1 mi)", "25:00", "8:03/mi", "5:00/km", "Beginner"],
  ["5K (3.1 mi)", "20:00", "6:26/mi", "4:00/km", "Intermediate"],
  ["10K (6.2 mi)", "50:00", "8:03/mi", "5:00/km", "Beginner"],
  ["10K (6.2 mi)", "40:00", "6:26/mi", "4:00/km", "Intermediate"],
  ["Half Marathon", "2:10:00", "9:55/mi", "6:10/km", "Beginner"],
  ["Half Marathon", "1:45:00", "8:01/mi", "4:59/km", "Intermediate"],
  ["Marathon", "4:30:00", "10:19/mi", "6:24/km", "Beginner"],
  ["Marathon", "3:30:00", "8:02/mi", "4:59/km", "Intermediate"],
  ["Marathon", "2:01:09", "4:38/mi", "2:52/km", "World Record (Kelvin Kiptum, 2023)"],
];

const DISTANCES = [
  { label: "1K", km: 1 }, { label: "5K", km: 5 }, { label: "10K", km: 10 },
  { label: "Half Marathon", km: 21.0975 }, { label: "Marathon", km: 42.195 }, { label: "Custom", km: 0 },
];

export default function PaceCalculator() {
  const [mode, setMode] = useState<CalcMode>("pace");
  const [distancePreset, setDistancePreset] = useState(1);
  const [customKm, setCustomKm] = useState(5);
  const [hours, setHours] = useState(0);
  const [minutes, setMinutes] = useState(30);
  const [seconds, setSeconds] = useState(0);
  const [paceMin, setPaceMin] = useState(6);
  const [paceSec, setPaceSec] = useState(0);

  const effectiveKm = DISTANCES[distancePreset].km || customKm;
  const totalTimeSec = hours * 3600 + minutes * 60 + seconds;
  const totalPaceSec = paceMin * 60 + paceSec;

  let result = "";
  let label = "";
  if (mode === "pace") {
    const paceSecPerKm = effectiveKm > 0 ? totalTimeSec / effectiveKm : 0;
    const paceSecPerMile = paceSecPerKm * 1.60934;
    result = `${formatTime(paceSecPerKm)}/km  -  ${formatTime(paceSecPerMile)}/mi`;
    label = "Your Pace";
  } else if (mode === "time") {
    const finishSec = totalPaceSec * effectiveKm;
    result = formatTime(finishSec);
    label = "Finish Time";
  } else {
    const km = totalPaceSec > 0 ? totalTimeSec / totalPaceSec : 0;
    result = `${km.toFixed(2)} km  -  ${(km / 1.60934).toFixed(2)} mi`;
    label = "Distance Covered";
  }

  return (
    <>
      <SEOHead
        title="Free Pace Calculator Online - Calculate Running Pace and Finish Time Instantly | CalcHive"
        description="Free online pace calculator. Calculate your running pace, finish time or distance for any race from 5K to marathon instantly. 100% free for all runners, no signup required."
        canonical="/pace-calculator"
        keywords="free pace calculator, running pace calculator free online, race pace calculator free, calculate running pace free, free 5K marathon pace calculator"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Running Pace Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free pace calculator to calculate running pace free, finish time, or distance for common race goals. This running pace calculator free online works as a race pace calculator free and free 5K marathon pace calculator for every runner.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex flex-wrap gap-2 mb-6">
            {[{ key: "pace" as CalcMode, label: "Calculate Pace" }, { key: "time" as CalcMode, label: "Calculate Finish Time" }, { key: "distance" as CalcMode, label: "Calculate Distance" }].map(m => (
              <button key={m.key} onClick={() => setMode(m.key)} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${mode === m.key ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{m.label}</button>
            ))}
          </div>
          <div className="mb-5">
            <p className="text-sm font-semibold text-foreground mb-2">Distance</p>
            <div className="flex flex-wrap gap-2 mb-2">
              {DISTANCES.map((d, i) => (
                <button key={d.label} onClick={() => setDistancePreset(i)} className={`px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${distancePreset === i ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{d.label}</button>
              ))}
            </div>
            {distancePreset === 5 && <input type="number" inputMode="decimal" value={customKm} min={0.1} step={0.1} onChange={e => setCustomKm(Number(e.target.value))} className="w-32 px-3 py-1.5 rounded-lg border border-input bg-background text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" placeholder="km" />}
          </div>
          {(mode === "pace" || mode === "distance") && (
            <div className="mb-5">
              <p className="text-sm font-semibold text-foreground mb-2">Time (hh:mm:ss)</p>
              <div className="flex items-center gap-2">
                {[{ label: "h", val: hours, set: setHours, max: 23 }, { label: "m", val: minutes, set: setMinutes, max: 59 }, { label: "s", val: seconds, set: setSeconds, max: 59 }].map(({ label: l, val, set, max }) => (
                  <div key={l} className="flex items-center gap-1">
                    <input type="number" min={0} max={max} value={val} onChange={e => set(Number(e.target.value))} className="w-16 px-2 py-2 rounded-lg border border-input bg-background text-sm text-center font-bold text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                    <span className="text-sm text-muted-foreground">{l}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
          {(mode === "time" || mode === "distance") && (
            <div className="mb-5">
              <p className="text-sm font-semibold text-foreground mb-2">Pace (min:sec per km)</p>
              <div className="flex items-center gap-2">
                <input type="number" min={0} max={59} value={paceMin} onChange={e => setPaceMin(Number(e.target.value))} className="w-16 px-2 py-2 rounded-lg border border-input bg-background text-sm text-center font-bold text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <span className="text-sm text-muted-foreground">min</span>
                <input type="number" min={0} max={59} value={paceSec} onChange={e => setPaceSec(Number(e.target.value))} className="w-16 px-2 py-2 rounded-lg border border-input bg-background text-sm text-center font-bold text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <span className="text-sm text-muted-foreground">sec</span>
              </div>
            </div>
          )}
          <motion.div key={result} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{label}</p>
              <p className="text-4xl font-black text-white tracking-tight" data-testid="result">{result}</p>
            </div>
          </motion.div>
        </section>
        <MedicalDisclaimer /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Running Pace for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Pace = Time  x  Distance</p>
            <p>Finish Time = Pace  x  Distance</p>
            <p>Distance = Time  x  Pace</p>
            <p className="text-xs text-muted-foreground mt-2">Speed (mph) = 60  x  Pace (min/mile)</p>
            <p className="text-xs text-muted-foreground">Pace (min/km) = Pace (min/mile)  x  0.62137</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Calculate Finish Time for 5K 10K Half Marathon and Marathon</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Race", "Finish Time", "Min/Mile", "Min/Km", "Level"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {RACE_PACES.map(([race, time, mpm, mpk, level]) => (
                  <tr key={`${race}-${time}`} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{race}</td>
                    <td className="py-2.5 px-4 text-teal-600 dark:text-teal-400 font-bold">{time}</td>
                    <td className="py-2.5 px-4 font-mono text-muted-foreground">{mpm}</td>
                    <td className="py-2.5 px-4 font-mono text-muted-foreground">{mpk}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{level}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Race Pace Tool for Every Runner</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to review your result quickly, compare reference ranges, and make a more informed health or fitness estimate without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/pace-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


